mapper.insert:
/* 공통: 파일 첨부 연결 저장 */
INSERT INTO FILE_ATTACH (
    FL_SN, FL_ATT_REF_TYPE_CD, FL_ATT_REF_SN, FL_ATT_SORT_NO, FL_ATT_SUBM_USR_SN
) VALUES (
    #{flSn}, #{flAttRefTypeCd}, #{flAttRefSn}, #{flAttSortNo}, #{flAttSubmUsrSn}
)

mapper.select:
/* 공통: 참조 건 첨부파일 경로 목록 */
SELECT F.FL_PATH
FROM FILE_ATTACH A
JOIN FILES F ON F.FL_SN = A.FL_SN
WHERE A.FL_ATT_REF_TYPE_CD = #{refTypeCd}
  AND A.FL_ATT_REF_SN = #{refSn}
ORDER BY A.FL_ATT_SORT_NO
